import java.util.*;

class Student {
    String name;
    List<Integer> grades = new ArrayList<>();

    Student(String name) {
        this.name = name;
    }
}

public class Main {
    public static void main(String[] args) {
        Runtime runtime = Runtime.getRuntime();

        System.out.println("Initial memory:");
        System.out.println("  Max: " + runtime.maxMemory() / 1024 / 1024 + " MB");
        System.out.println("  Total: " + runtime.totalMemory() / 1024 / 1024 + " MB");
        System.out.println("  Free: " + runtime.freeMemory() / 1024 / 1024 + " MB");

        // Create many objects
        List<Student> students = new ArrayList<>();
        for (int i = 0; i < 10000; i++) {
            Student s = new Student("Student" + i);
            for (int j = 0; j < 10; j++) {
                s.grades.add((int)(Math.random() * 100));
            }
            students.add(s);
        }

        System.out.println("\nAfter creating 10000 objects:");
        System.out.println("  Free: " + runtime.freeMemory() / 1024 / 1024 + " MB");

        // Remove references (eligible for GC)
        students.clear();
        System.gc();  // Hint to run GC

        System.out.println("\nAfter clearing and GC:");
        System.out.println("  Free: " + runtime.freeMemory() / 1024 / 1024 + " MB");
    }
}
